  //    в””в”Җв”Җ .bpc-noc-right   (relГіgio + data)

  function buildNocLabel() {
    try {
      const tSrv = context.grafana && context.grafana.templateSrv;
      if (!tSrv) return CFG_HEADER.nocLabel;
      const hv = tSrv.getVariables().find(function(v) { return v.name === 'host'; });
      const router = (hv && hv.current && hv.current.value) || '';
      const agName = (hv && hv.current && hv.current.text) || '';
      if (!router || router === 'All' || router === '$__all') return 'AGГҠNCIAS В· NГҚVEL 5 В· INTERFACES';
      return 'AGГҠNCIAS В· NГҚVEL 5 В· INTERFACES В· ' + router
        + (agName && agName !== router ? ' В· ' + agName : '');
    } catch(e) { return CFG_HEADER.nocLabel; }
  }

  function renderHeader(el) {
    const C = CFG_HEADER;
    const Z = CFG_SIZES;
    C.nocLabel = buildNocLabel();

    // LogГіtipo: tenta carregar a imagem; se falhar, mostra fallback textual
    const logoHTML = C.logoUrl
      ? `<img src="${C.logoUrl}"
              height="${Z.logo.height}"
              class="bpc-noc-logo"
              onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">
         <div class="bpc-noc-logo-fallback" style="display:none">${C.title}</div>`
