  // в”Җв”Җ Aguardar #bpc-header-root no DOM в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  //
  //  O Grafana injecta os painГ©is de forma assГӯncrona; o elemento pode
  //  ainda nГЈo existir quando este script executa.
  //  Polling a cada 50ms com timeout de 10s.

  const t0 = Date.now();
  const poll = setInterval(() => {
    const el = document.getElementById('bpc-header-root');
    if (el) {
      clearInterval(poll);
      renderHeader(el);
      return;
    }
    if (Date.now() - t0 > 10000) {
      clearInterval(poll);
      console.warn('[BPC] Header: #bpc-header-root nГЈo encontrado apГіs 10s');
    }
  }, 50);

