(function bootstrap() {

  const VERSION = CFG_META.version;


  // в”Җв”Җ Guard вҖ” evita dupla inicializaГ§ГЈo в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  //
  //  Se jГЎ existir uma instГўncia com a mesma versГЈo E todos os componentes
  //  presentes, termina sem fazer nada.
  //  Se o estado for parcial (crash parcial, recarga do painel), reinicializa.

  if (window.BPC && window.BPC.version === VERSION) {
    const ok =
      !!document.getElementById('bpc-global-css') &&
      typeof (window.BPC.utils && window.BPC.utils.waitForElement) === 'function' &&
      typeof window.BPC.rpc === 'function' &&
      typeof window.BPC.log === 'function';
    if (ok) return;
    // Init em curso noutro afterRender concorrente вҖ” nГЈo re-inicializar
    if (window.BPC._initPending) return;
    console.warn('[BPC] Estado parcial вҖ” reinicializando (' + VERSION + ')');
    window.BPC._ready = false;
    window.BPC.rpc = null;
  }
  if (!window.BPC) window.BPC = {};
  window.BPC._initPending = true;


  // в”Җв”Җ Namespace window.BPC в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

