}

function fmtBps(v) {
  if (v == null || isNaN(v) || v < 0) return 'вҖ”'
  if (v >= 1e9) return (v / 1e9).toFixed(2) + ' Gbps'
  if (v >= 1e6) return (v / 1e6).toFixed(1) + ' Mbps'
